  ('disabled-c5fb3965-moex-00191', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-55d283b0', 'sub-disabled-c5fb3965-05', NULL, 'single_choice', '行政行為不得與法律相牴觸，此係涉及下列何種原則？', '["平等原則", "法律優位原則", "信賴保護原則", "比例原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00192', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-55d283b0', 'sub-disabled-c5fb3965-05', NULL, 'single_choice', '依司法院大法官解釋及憲法法庭裁判意旨，下列何者與平等原則有違？', '["中央警察大學研究所以色盲為差別待遇分類，符合重要公益，難謂與其 所欲達成之目的欠缺實質關聯性", "立法者得鑒於男女生理之差異，在服兵役事項上為不同之處置", "司法院釋字第728號解釋宣示，依規約得排除女性為祭祀公業之派下員", "立法機關基於憲法價值體系，得斟酌規範事物性質之差異，於服公職事 項上為合理之區別對待"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00193', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-55d283b0', 'sub-disabled-c5fb3965-05', NULL, 'single_choice', '有關法律上經常被引用的「誠實信用」原則，下列何者錯誤？', '["誠實信用原則為民法上之原則，公法領域並無適用", "「誠實信用」本身為不確定法律概念的一種", "公、私法上之法律行為，均應當遵守誠實信用原則", "從誠實信用原則可以導出「禁止權利濫用」的要求"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00194', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-55d283b0', 'sub-disabled-c5fb3965-05', NULL, 'single_choice', '公法領域中，行政行為相對人主張信賴保護，其所存在之「信賴」必須具 有保護之價值。有關保護價值之說明，下列何者正確？', '["以詐欺、脅迫手段獲得之利益，也有保護價值", "信賴非授益行政處分，不適用信賴保護原則", "法規未曾預先保留廢止權力者，必然無保護之價值", "明知行政處分違法者，無保護價值"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00195', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-55d283b0', 'sub-disabled-c5fb3965-05', NULL, 'single_choice', '依行政罰法之規定，行政機關對結果犯裁處行政罰，關於裁處權之時效， 下列何者正確？', '["並無裁處權時效", "其裁處權時效自違反行政法上義務之行為終了時起算", "其裁處權時效自結果發生時起算", "由行政機關裁量決定自何時起算"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00196', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-55d283b0', 'sub-disabled-c5fb3965-05', NULL, 'single_choice', '主管機關在開放之山域及水域所形成之國家公園登山口設置顯著警告標 誌，呼籲遊客在颱風警報發布後勿冒險登山。登山客甲不理會登山口之警 告標誌，在颱風警報發布後，仍進入國家公園登山，最終因天候不佳遭遇 山難。主管機關對於此一山難，是否應負國家賠償責任？', '["應負國家賠償責任，因為國家公園之山域乃是自然公物", "應負國家賠償責任，因為國家對人民之生命有保護義務", "應負國家賠償責任，因為警告標誌對人民並不具拘束力", "不負國家賠償責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00197', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-55d283b0', 'sub-disabled-c5fb3965-05', NULL, 'single_choice', '行政機關扣留得沒入或可為證據之物者，關於物之所有權人的權利救濟， 下列何者錯誤？', '["應向扣留機關聲明異議", "聲明異議，扣留機關認為無理由者，應送直接上級機關決定之", "對於直接上級機關之決定不服者，僅得直接向行政法院聲明不服", "聲明異議不影響扣留或裁處程序之進行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00198', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-55d283b0', 'sub-disabled-c5fb3965-05', NULL, 'single_choice', '警察與逃犯槍戰時，流彈不小心傷及附近民眾，如果警察係依警械使用條 例規定使用警械，並無國家賠償法之故意或過失，民眾應如何向國家請求 補償？', '["依警械使用條例規定請求補償", "人民可依國家賠償法請求國家賠償", "人民無任何請求補償的權利", "人民可直接向該警察求償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00199', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-55d283b0', 'sub-disabled-c5fb3965-05', NULL, 'single_choice', '依行政法院實務見解，下列有關訴願決定之敘述，何者錯誤？', '["訴願無理由者，受理訴願機關應以訴願決定駁回之", "訴願事件涉及地方自治團體之地方自治事務者，其受理訴願之上級機關 僅就原行政處分之合法性進行審查決定", "訴願有理由者，受理訴願機關得視事件之情節，逕為發回原處分機關重 為處分，但重為處分時，於訴願人表示不服之範圍內，不得為更不利益 之變更", "提起訴願因逾法定期間而為不受理決定時，原行政處分機關仍得依職權 撤銷原處分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00200', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-55d283b0', 'sub-disabled-c5fb3965-05', NULL, 'single_choice', '人民對內政部之行政處分不服，提起訴願，關於受理訴願機關之審查，下 列何者正確？', '["得審查內政部行政處分之合法性與適當性", "僅能審查內政部行政處分之合法性，不得審查內政部行政處分之適當性", "僅能審查內政部行政處分之適當性，不得審查內政部行政處分之合法性", "僅能審查內政部羈束處分之合法性，不得審查內政部裁量處分之合法性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL)
